final:
module RefModule (
    input clk,
    input rst,
    output reg [1:0] gray
);

reg [1:0] obf_binary;

always @(posedge clk or posedge rst) begin
    if (rst) begin
        obf_binary <= 2'b00;
    end else begin
        obf_binary <= obf_binary + 1;
    end
end

always @(obf_binary) begin
    gray = obf_binary ^ (obf_binary >> 1);
end

endmodule
